cards.back:
const http = require('http');

const server = http.createServer((req, res) => {
  res.statusCode = 200;
  res.setHeader('Content-Type', 'text/plain; charset=utf-8');
  res.end('Hola mundo desde Node.js!');
});

server.listen(3000, () => {
  console.log('Servidor en funcionamiento en http://localhost:3000');
});

Una variable es un espacio de memoria donde almacenamos datos de manera temporal, accesibles en cualquier momento durante la ejecución del programa.

Se declara con let:
let miValor;
let dato = 5;
let dato;
dato = 5;

Se utiliza para valores numéricos, tanto enteros como decimales.

let numEntero = 5;
let numDecimal = 3.14;

console.log(typeof numDecimal); // "number"

Solo puede contener true o false, y se utiliza para representar estados.

let encendido = true;
let apagado = false;

Representa cadenas de caracteres, entre comillas simples, dobles o backticks (template strings).

let mensaje = "Hola mundo";
let otroMensaje = 'Buen día';
let completo = `Hola, ${nombre}!`;  // template string

Mediante el módulo readline:

const readline = require('readline');
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

rl.question('¿Cómo te llamas? ', (nombre) => {
  console.log(`Hola, ${nombre}!`);
  rl.close();
});

Es una forma compacta de hacer una asignación en función de una condición.

Sintaxis: condición ? valor_si_cierto : valor_si_falso

Ejemplo:
let numero = 10;
let mayorQueCinco = numero > 5 ? "sí" : "no";
console.log(mayorQueCinco); // "sí"

if:
if (condición) { /* código */ }

if / else:
if (condición) { /* código */ }
else { /* código si falso */ }

if / else if / else:
if (nota < 5) { console.log("Suspenso"); }
else if (nota < 7) { console.log("Bien"); }
else if (nota < 9) { console.log("Notable"); }
else { console.log("Excelente"); }

Se comprueban las condiciones en orden hasta que se cumpla una.

Es una alternativa más legible a múltiples if/else if. Comprueba un valor y ejecuta el bloque correspondiente al caso.

switch (color) {
  case "rojo":
    console.log("rojo");
    break;
  case "amarillo":
    console.log("amarillo");
    break;
  default:
    console.log("otro color");
}

Es necesario usar break para evitar que se ejecuten los casos siguientes.

let i = 1;

while (i <= 5) {
  console.log(i);
  i++;
}
// Resultado: 1 2 3 4 5

Ejecuta el código mientras la condición sea cierta. Si la condición es falsa desde el principio, no se ejecuta ninguna vez.

do...while garantiza que el bloque se ejecuta como mínimo una vez, ya que la condición se comprueba después de la primera ejecución.

let i = 1;
do {
  console.log(i);
  i++;
} while (i <= 5);
// Resultado: 1 2 3 4 5

En while, la condición se evalúa antes; si es falsa de entrada, no se ejecuta ninguna vez.

for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Resultado: 0 1 2 3 4

Reúne las tres partes (inicialización, condición, actualización) en una sola línea.

Buena práctica para arrays:
for (let i = 0, len = array.length; i < len; i++) {
  // Evita recalcular .length en cada iteración
}

Recorre todos los elementos de un array y ejecuta una función para cada uno de ellos. No retorna ningún array nuevo.

let valores = [10, 20, 30];

valores.forEach(function(valor, index) {
  console.log("Posición " + index + ": " + valor);
});

// Con función flecha:
valores.forEach((valor, i) => console.log(i + ": " + valor));

Recorre las propiedades (claves) de un objeto.

let coche = { marca: "Toyota", modelo: "Yaris", año: 2020 };

for (let clave in coche) {
  console.log(clave + ": " + coche[clave]);
}
// marca: Toyota, modelo: Yaris, año: 2020

Con corchetes []:

let vacia = [];
let numeros = [1, 2, 3, 4];
let nombres = ["Ana", "Pau", "Joan"];
let mixto = [1, "hola", true, [10, 20]];

También con constructor (no recomendado):
let colores = new Array("rojo", "azul", "verde");

Los arrays pueden contener cualquier tipo de dato, incluso mezclados.

Un objeto literal es una forma directa de crear un objeto con claves (propiedades) y valores.

let persona = {
  nombre: "Ana",
  edad: 28,
  vive: true
};

Cada propiedad tiene una clave (ej. "nombre") y un valor asociado (ej. "Ana").

Es una función que forma parte de un objeto. Permite definir comportamientos relacionados con el objeto.

let persona = {
  nombre: "Ana",
  edad: 28,
  saludar() {
    console.log(`Hola! Soy ${this.nombre}.`);
  }
};

persona.saludar();  // "Hola! Soy Ana."

this hace referencia al objeto mismo.

Con la palabra clave delete:

delete persona.vive;

También se pueden eliminar métodos, ya que internamente son propiedades como cualquier otra:

delete persona.saludar;
console.log(persona.saludar); // undefined

Es una estructura de datos compleja donde un array contiene objetos con la misma estructura. Ideal para representar colecciones de elementos.

let libros = [
  { titulo: "1984", autor: "George Orwell", año: 1949 },
  { titulo: "Crimen y castigo", autor: "Dostoievski", año: 1866 },
  { titulo: "La sombra del viento", autor: "Carlos Ruiz Zafón", año: 2001 }
];

Muy útil para datos de APIs y bases de datos.

Es un objeto que contiene arrays como valores de algunas propiedades. Permite representar características con múltiples valores asociados.

let usuario = {
  nombre: "Marta",
  edad: 22,
  aficiones: ["lectura", "escalada", "viajar"]
};

Acceso: usuario.aficiones[1]  → "escalada"
Modificar: usuario.aficiones.push("cine");

Una clase es un esquema o plantilla que define cómo deben ser los objetos que se creen a partir de ella. Agrupa propiedades y métodos.

class Persona {
  constructor(nombre, edad) {
    this.nombre = nombre;
    this.edad = edad;
  }

  saludar() {
    console.log(`Hola, soy ${this.nombre} y tengo ${this.edad} años.`);
  }
}

Las clases se introdujeron en ES6 (2015).

Usando la palabra clave new:

const p1 = new Persona("Ana", 30);
const p2 = new Persona("Joan", 22);

p1.saludar();  // Hola, soy Ana y tengo 30 años.
p2.saludar();  // Hola, soy Joan y tengo 22 años.

Cada instancia tiene sus propios valores pero comparte el comportamiento definido en la clase.

Usando el símbolo # antes del nombre de la propiedad (desde ES2022).

class Cuenta {
  #saldo;  // propiedad privada

  constructor(titular) {
    this.titular = titular;
    this.#saldo = 0;
  }

  ingresar(cantidad) {
    this.#saldo += cantidad;
  }

  verSaldo() {
    return this.#saldo;
  }
}

Las propiedades privadas solo pueden accederse desde dentro de la clase.

Permiten definir cómo se lee (get) o escribe (set) una propiedad de forma controlada, con una sintaxis externa natural.

class Cuenta {
  #saldo;

  get saldo() {
    return this.#saldo.toFixed(2) + " €";
  }

  set saldo(cantidad) {
    if (cantidad >= 0) {
      this.#saldo = cantidad;
    } else {
      console.log("No se permite saldo negativo.");
    }
  }
}

// Uso:
cuenta.saldo = 200;      // set
console.log(cuenta.saldo); // get → "200.00 €"

Usando las palabras clave extends y super:

class Animal {
  constructor(nombre) {
    this.nombre = nombre;
  }
  hablar() {
    console.log(`${this.nombre} hace un sonido.`);
  }
}

class Perro extends Animal {
  hablar() {
    console.log(`${this.nombre} ladra.`);
  }
}

const rex = new Perro("Rex");
rex.hablar();  // "Rex ladra."

Permite definir métodos con el mismo nombre pero comportamientos diferentes, según el tipo de objeto que los implementa.

En JavaScript se consigue mediante la sobreescritura de métodos en clases hijas.

class Empleado {
  saludar() { console.log("Hola, soy un empleado."); }
}

class Jefe extends Empleado {
  saludar() { console.log("Hola, soy el jefe!"); }
}

Ambos tienen saludar() pero con comportamientos diferentes.

Son el verdadero sistema de herencia de JavaScript. Cada objeto tiene un enlace interno a su prototipo. Si no encuentra una propiedad o método en sí mismo, la busca en el prototipo del que deriva (cadena de prototipos).

Las clases (ES6) son solo una sintaxis más clara para trabajar con prototipos.

// Forma antigua (sin clases):
function Persona(nombre) {
  this.nombre = nombre;
}
Persona.prototype.saludar = function() {
  console.log(`Hola, soy ${this.nombre}`);
};

class Asignatura {
  constructor(nombre) {
    this.nombre = nombre;
    this.notas = [];
  }
  añadirNota(nota) {
    if (nota >= 0 && nota <= 10) this.notas.push(nota);
  }
  get media() {
    const total = this.notas.reduce((acc, n) => acc + n, 0);
    return this.notas.length ? (total / this.notas.length).toFixed(2) : "Sin notas";
  }
}

class Estudiante {
  #dni;
  constructor(nombre, dni) {
    this.nombre = nombre;
    this.#dni = dni;
    this.asignaturas = [];
  }
  get identificador() {
    return `Estudiante: ${this.nombre} (DNI: ${this.#dni})`;
  }
  añadirAsignatura(asignatura) {
    this.asignaturas.push(asignatura);
  }
  mostrarCalificaciones() {
    console.log(this.identificador);
    this.asignaturas.forEach(a => console.log(`- ${a.nombre}: media = ${a.media}`));
  }
}

class Animal {
  constructor(nombre) {
    this.nombre = nombre;
  }
  hacerSonido() {
    console.log(`${this.nombre} hace un sonido indefinido.`);
  }
}

class Perro extends Animal {
  hacerSonido() {
    console.log(`${this.nombre} ladra: ¡guau!`);
  }
}

class Gato extends Animal {
  hacerSonido() {
    console.log(`${this.nombre} maúlla: ¡miau!`);
  }
}

class Pajaro extends Animal {
  hacerSonido() {
    console.log(`${this.nombre} canta: ¡pío pío!`);
  }
}

// Uso polimórfico:
const animales = [new Perro("Rex"), new Gato("Luna"), new Pajaro("Kiwi")];
animales.forEach(a => a.hacerSonido());

Propiedad: parentNode

Ejemplo:
const menu = document.getElementById('menu');
console.log(menu.parentNode);

- Devuelve el nodo padre del elemento
- Para el elemento <nav>, el padre seria el <header>

Se puede usar querySelector sobre cualquier elemento para buscar SOLO dentro de sus descendientes.

Ejemplo:
const menu = document.getElementById('menu');
const listaMenu = menu.querySelector('ul');

- Busca el primer <ul> que sea descendiente de #menu
- Limita el area de busqueda, mejor rendimiento

Propiedad: children.length

Ejemplo:
const listaMenu = menu.querySelector('ul');
console.log(listaMenu.children.length);

- children devuelve solo elementos HTML (ignora nodos de texto)
- childNodes.length incluiria nodos de texto

children es una coleccion indexada (como un array).

Ejemplos:
const listaMenu = menu.querySelector('ul');

// Primer hijo (indice 0)
const primerLi = listaMenu.children[0];

// Tercer hijo (indice 2)
const tercerLi = listaMenu.children[2];

// Nota: los indices empiezan en 0

Metodo: querySelectorAll('selector')

Ejemplos:
// Todos los h3 con clase titulo-articulo
const titulos = document.querySelectorAll('.titulo-articulo');

// Todos los enlaces dentro de #menu
const enlaces = document.querySelectorAll('#menu a');

- Devuelve NodeList estatica
- Acepta cualquier selector CSS valido

Operador += con textContent

Ejemplo:
const tituloDestacado = document.querySelector('.articulo.destacado .titulo-articulo');
tituloDestacado.textContent += ' (DESTACADO)';

- += concatena texto al existente
- Seleccion combinada: .clase1 .clase2 (descendiente)

Selector CSS: ancestro descendiente (con espacio)

Ejemplo:
// <p> dentro de #contacto
const parrafo = document.querySelector('#contacto p');

// .titulo-articulo dentro de .articulo.destacado
const titulo = document.querySelector('.articulo.destacado .titulo-articulo');

- El espacio indica relacion descendiente
- Puede ser hijo directo o indirecto

Metodo: element.setAttribute('nombre', 'valor')

Ejemplo:
const enlace = document.querySelector("a");
enlace.setAttribute("href", "https://www.ioc.cat");
enlace.setAttribute("target", "_blank");

- Crea el atributo si no existe
- Sobrescribe el valor si ya existe
- Funciona con cualquier atributo HTML

Atributos personalizados HTML5 para almacenar informacion adicional.

HTML:
<li data-precio="12.5" data-id="123">Producto X</li>

JavaScript - Acceso via dataset:
const item = document.querySelector("li");
const precio = item.dataset.precio;      // "12.5"
const id = item.dataset.id;              // "123"

// Modificar
item.dataset.precio = "15.0";

- El guion se convierte en camelCase: data-product-id → dataset.productId

Metodo: document.createElement('nombreEtiqueta')

Ejemplo:
// Crear un nuevo elemento li
const nuevoLi = document.createElement("li");

// Configurar contenido
nuevoLi.textContent = "Elemento nuevo";

// Insertar en el DOM
lista.appendChild(nuevoLi);

Pasos tipicos:
1. Crear el elemento
2. Configurar (texto, atributos, clases...)
3. Insertar en el arbol DOM

Metodo: document.createTextNode('texto')

Ejemplo:
const nuevoLi = document.createElement("li");
const texto = document.createTextNode("Texto del elemento");

// Unir texto al elemento
nuevoLi.appendChild(texto);

// Insertar en la lista
lista.appendChild(nuevoLi);

Alternativa mas sencilla:
nuevoLi.textContent = "Texto del elemento";

Metodo: padre.appendChild(nuevoHijo)

Ejemplo:
const lista = document.getElementById("lista");
const nuevoLi = document.createElement("li");
nuevoLi.textContent = "Ultimo elemento";

lista.appendChild(nuevoLi);

- Anade el elemento como ULTIMO hijo del padre
- Si el elemento ya existe en el DOM, lo MUEVE a la nueva posicion
- Metodo clasico, compatible con todos los navegadores

Metodo: padre.insertBefore(nuevoNodo, nodoReferencia)

Ejemplo:
const lista = document.getElementById("lista");
const primerElemento = lista.firstElementChild;
const nuevoLi = document.createElement("li");

// Insertar antes del primer elemento
lista.insertBefore(nuevoLi, primerElemento);

- Primer parametro: nuevo nodo a insertar
- Segundo parametro: nodo antes del cual insertar
- Si segundo parametro es null, inserta al final

append() → Inserta al FINAL como ultimo hijo
prepend() → Inserta al PRINCIPIO como primer hijo

Ejemplos:
const lista = document.getElementById("lista");

// Al final
lista.append(nuevoElemento);

// Al principio
lista.prepend(nuevoElemento);

Ventajas sobre appendChild:
- Pueden insertar multiples elementos a la vez
- Aceptan strings (se convierten en nodos de texto)
- Mas flexible y modernos

before() → Inserta antes del elemento actual
after() → Inserta despues del elemento actual

Ejemplos:
const referencia = document.querySelector(".elemento");

// Insertar antes
referencia.before(nuevoElemento);

// Insertar despues
referencia.after(nuevoElemento);

- Se llaman sobre el elemento de referencia (no sobre el padre)
- No requieren conocer el elemento padre

Problema: los atributos id deben ser UNICOS en la pagina.

Ejemplo problematico:
const original = document.getElementById("elemento-unico");
const clon = original.cloneNode(true);
lista.appendChild(clon);

// ¡Ahora hay dos elementos con el mismo id!

Soluciones:
1. Eliminar el id del clon:
clon.removeAttribute("id");

2. Cambiar el id del clon:
clon.id = "elemento-unico-2";

Recomendacion: usar clases en lugar de ids para elementos reutilizables.

Patron util para crear elementos dinamicos:

HTML:
<li id="plantilla" style="display: none;">
  <span class="titulo"></span>
</li>

JavaScript:
function agregarElemento(texto) {
  const plantilla = document.getElementById("plantilla");
  const clon = plantilla.cloneNode(true);

  clon.removeAttribute("id");    // Evitar duplicar id
  clon.style.display = "";       // Hacer visible
  clon.querySelector(".titulo").textContent = texto;

  lista.appendChild(clon);
}

Ventaja: se define la estructura en HTML y se clona dinamicamente.

Metodo clasico: padre.removeChild(hijo)

Ejemplo:
const elemento = document.querySelector(".elemento");
elemento.parentNode.removeChild(elemento);

Obtener primero el padre:
const padre = document.getElementById("contenedor");
const hijo = document.getElementById("hijo");
padre.removeChild(hijo);

- Requiere conocer el elemento padre
- Metodo clasico, maxima compatibilidad
- remove() es mas moderno y sencillo

Opcion 1: innerHTML vacio
contenedor.innerHTML = "";

Opcion 2: bucle con removeChild (metodo clasico)
while (contenedor.firstChild) {
  contenedor.removeChild(contenedor.firstChild);
}

Opcion 3: replaceChildren (moderno)
contenedor.replaceChildren();

La opcion 1 (innerHTML) es la mas corta y comun.
La opcion 2 es util para navegadores muy antiguos.

Metodo: padre.replaceChild(nuevoNodo, nodoViejo)

Ejemplo:
const viejo = document.getElementById("banner-viejo");
const nuevo = document.createElement("div");
nuevo.textContent = "Nuevo banner";

viejo.parentNode.replaceChild(nuevo, viejo);

- Requiere referencia al elemento padre
- Primer parametro: nuevo elemento
- Segundo parametro: elemento a reemplazar
- El elemento viejo se elimina completamente

Metodo moderno: replaceWith()

Ejemplo:
const viejo = document.getElementById("elemento-viejo");
const nuevo = document.createElement("div");
nuevo.textContent = "Contenido nuevo";

viejo.replaceWith(nuevo);

- Se llama sobre el elemento a reemplazar
- No requiere conocer el padre
- Mas intuitivo que replaceChild
- Puede recibir multiples elementos o strings

Metodo: elemento.addEventListener('tipoEvento', funcionManejadora)

Ejemplo:
const boton = document.getElementById('miBoton');
boton.addEventListener('click', function() {
  console.log('¡Clic!');
});

Parametros:
1. Tipo de evento (string): 'click', 'mouseenter', 'submit'...
2. Funcion manejadora (callback): se ejecuta cuando ocurre el evento
3. Opciones (opcional): objeto con opciones como capture, once, passive

Metodo: elemento.removeEventListener('tipoEvento', funcionReferencia)

Ejemplo:
// Definir la funcion por separado
function manejadorClick() {
  console.log('Clic detectado');
}

// Añadir listener
boton.addEventListener('click', manejadorClick);

// Eliminar listener (misma referencia de funcion)
boton.removeEventListener('click', manejadorClick);

IMPORTANTE: Debe ser la MISMA referencia de funcion, no una funcion anonima.

Porque removeEventListener requiere la MISMA referencia de funcion que se uso en addEventListener.

// ❌ NO FUNCIONA:
boton.addEventListener('click', function() { ... });
boton.removeEventListener('click', function() { ... });

// ✅ FUNCIONA:
function miFuncion() { ... }
boton.addEventListener('click', miFuncion);
boton.removeEventListener('click', miFuncion);

Las funciones anonimas son objetos diferentes cada vez que se crean.

Objeto que el navegador pasa automaticamente a la funcion manejadora con informacion sobre el evento ocurrido.

Ejemplo:
boton.addEventListener('click', function(event) {
  console.log(event.type);     // 'click'
  console.log(event.target);   // elemento donde ocurrio el clic
  console.log(event.clientX);  // coordenada X del clic
});

Tambien puede escribirse como 'e' o 'evt' por convencion.

Ejemplo con querySelectorAll:

const items = document.querySelectorAll('#llista li');

items.forEach(function(item) {
  item.addEventListener('click', function(event) {
    console.log('Clic en:', item.textContent);
    console.log('data-id:', item.dataset.id);
  });
});

- querySelectorAll devuelve NodeList
- forEach itera sobre cada elemento
- Cada elemento tiene su propio listener

Cuando un evento ocurre en un elemento, este se propaga hacia arriba en el arbol DOM (del hijo al padre, al abuelo, etc.).

Ejemplo:
<body>
  <div id="contenedor">
    <button id="boton">Clic</button>
  </div>
</body>

// Si hay listeners en button, div y body:
// 1. Se ejecuta el listener del BUTTON
// 2. Se ejecuta el listener del DIV
// 3. Se ejecuta el listener del BODY

Fase de propagacion = evento sube desde el target hasta el document.

Metodo: event.stopPropagation()

Ejemplo:
const boton = document.getElementById('boto-propagacio');
const contenedor = document.getElementById('contenidor-propagacio');

boton.addEventListener('click', function(event) {
  event.stopPropagation();  // ← Detiene la propagacion
  console.log('Clic en boton (no sube al contenedor)');
});

contenedor.addEventListener('click', function() {
  console.log('Clic en contenedor');
});

// Al hacer clic en el boton:
// Solo se ejecuta el listener del boton,
// NO se ejecuta el del contenedor

CLICK - Clic completo (presionar y soltar)
MOUSEDOWN - Boton del raton presionado
MOUSEUP - Boton del raton soltado

MOUSEENTER - Raton entra en el elemento
MOUSELEAVE - Raton sale del elemento

MOUSEMOVE - Raton se mueve sobre el elemento

Ejemplo hover:
elemento.addEventListener('mouseenter', function() {
  this.style.backgroundColor = '#e6f7ff';
});

elemento.addEventListener('mouseleave', function() {
  this.style.backgroundColor = '';
});

Accediendo a la propiedad style del elemento:

// En el manejador de evento:
elemento.style.backgroundColor = '#e6f7ff';
elemento.style.color = 'red';
elemento.style.fontSize = '20px';

// Notas importantes:
// - Las propiedades CSS con guion se convierten a camelCase
//   background-color → backgroundColor
//   font-size → fontSize

// Para eliminar un estilo inline:
elemento.style.backgroundColor = '';  // Vuelve al valor por defecto

Tres formas de vaciar un elemento:

// 1. innerHTML vacio (mas directo)
elementoLog.innerHTML = '';

// 2. Reemplazar todos los hijos (moderno)
elementoLog.replaceChildren();

// 3. Bucle eliminando hijos (clasico)
while (elementoLog.firstChild) {
  elementoLog.removeChild(elementoLog.firstChild);
}

Ejemplo tipico - boton limpiar log:
botonNeteja.addEventListener('click', function() {
  log.innerHTML = '';
});

Ejemplo de funcion auxiliar para añadir mensajes:

function afegeixAlLog(text) {
  // 1. Crear elemento li
  const nouLi = document.createElement('li');

  // 2. Añadir texto
  nouLi.textContent = text;

  // 3. Añadir al final de la lista
  log.appendChild(nouLi);
}

// Uso en listeners:
targeta.addEventListener('click', function(e) {
  const text = `Hem clicat a ${e.target.nodeName}`;
  afegeixAlLog(text);
});

Se dispara cuando el HTML ha sido completamente cargado y parseado.

Ejemplo:
document.addEventListener('DOMContentLoaded', function() {
  // El DOM esta listo para manipular
  const boton = document.getElementById('miBoton');
  const lista = document.getElementById('miLista');

  // Configurar listeners...
  boton.addEventListener('click', ...);
});

IMPORTANTE: Siempre envolver el codigo DOM en este evento para asegurar que los elementos existen.

Si se añade el MISMO listener (misma funcion referencia) multiples veces:

// Solo se ejecuta UNA VEZ por evento:
function miFuncion() { console.log('click'); }

elemento.addEventListener('click', miFuncion);
elemento.addEventListener('click', miFuncion);  // Ignorado

// Pero si son funciones DIFERENTES (anonimas):
elemento.addEventListener('click', function() { ... });
elemento.addEventListener('click', function() { ... });
// Se ejecutan AMBAS (son funciones distintas)

El navegador detecta duplicados solo si es la misma referencia.

Usando la propiedad dataset del elemento:

HTML:
<li data-id="123" data-rol="admin">Usuario</li>

JavaScript:
items.forEach(function(item) {
  item.addEventListener('click', function() {
    const id = item.dataset.id;      // "123"
    const rol = item.dataset.rol;    // "admin"
    console.log(`ID: ${id}, Rol: ${rol}`);
  });
});

// Para convertir a numero:
const idNumerico = parseInt(item.dataset.id);

Patron completo para botones de activar/desactivar:

// Funciones nombradas para poder eliminarlas luego
function gestionarClick() {
  console.log('Clic detectado');
}

function activarListener() {
  targeta.addEventListener('click', gestionarClick);
  afegeixAlLog('Listener activado');
}

function desactivarListener() {
  targeta.removeEventListener('click', gestionarClick);
  afegeixAlLog('Listener desactivado');
}

// Botones de control
botoActivar.addEventListener('click', activarListener);
botoDesactivar.addEventListener('click', desactivarListener);

Ejemplo practico con data attributes:

const listaItems = document.querySelectorAll('#llista li');

listaItems.forEach(function(elemento) {
  elemento.addEventListener('click', function() {
    const texto = elemento.textContent;
    const id = elemento.dataset.id;

    afegeixAlLog(
      `Hem clicat: ${texto} (data-id: ${id})`
    );
  });
});

// HTML correspondiente:
// <li data-id="1">Elemento 1</li>
// <li data-id="2">Elemento 2</li>

PASOS TIPICOS:

1. Esperar a DOMContentLoaded
2. Seleccionar elementos del DOM
3. Definir funciones manejadoras (nombradas si se necesitan eliminar)
4. Añadir listeners con addEventListener
5. En el manejador:
   - Usar event.target/currentTarget
   - Ejecutar logica
   - Actualizar DOM si es necesario
6. Opcional: eliminar listeners con removeEventListener

EJEMPLO:
document.addEventListener('DOMContentLoaded', function() {
  const boton = document.getElementById('boton');

  boton.addEventListener('click', function(e) {
    console.log('Clic en:', e.target);
  });
});

Funcion auxiliar para añadir mensajes al log:

function afegeixAlLog(text) {
  const li = document.createElement('li');
  li.textContent = text;
  log.appendChild(li);
}

USO EN LISTENERS:
targeta.addEventListener('click', function(e) {
  afegeixAlLog('Hem clicat a la targeta');
});

Funcion que muestra la diferencia entre currentTarget y target:

function gestionarClicTargeta(event) {
  const nomCurrent = event.currentTarget.tagName;
  const nomTarget = event.target.tagName;

  afegeixAlLog(
    `Hem clicat (currentTarget: ${nomCurrent}, target: ${nomTarget})`
  );
}

- currentTarget: elemento con el listener (DIV #targeta)
- target: elemento exacto clicado (p, button, h2...)

Usar forEach sobre NodeList de querySelectorAll:

const elementsLlista = llista.querySelectorAll('li');

elementsLlista.forEach((element) => {
  element.addEventListener('click', () => {
    const text = element.textContent.trim();
    const id = element.dataset.id;
    afegeixAlLog(`Hem clicat: ${text} (data-id: ${id})`);
  });
});

Nota: Se lee dataset.id para obtener el atributo data-id

ACTIVAR listener:
botoActivarClick.addEventListener('click', () => {
  targeta.addEventListener('click', gestionarClicTargeta);
  afegeixAlLog('Afegim el listener de clic');
});

DESACTIVAR listener:
botoDesactivarClick.addEventListener('click', () => {
  targeta.removeEventListener('click', gestionarClicTargeta);
  afegeixAlLog('Eliminem el listener de clic');
});

IMPORTANTE: usar la misma referencia de funcion (gestionarClicTargeta)

Funciones para efecto hover en la targeta:

function gestionarMouseEnterTargeta() {
  targeta.style.backgroundColor = '#e6f7ff';
  afegeixAlLog('El ratoli ha entrat a la targeta');
}

function gestionarMouseLeaveTargeta() {
  targeta.style.backgroundColor = '';
  afegeixAlLog('El ratoli ha sortit de la targeta');
}

// Activar hover
targeta.addEventListener('mouseenter', gestionarMouseEnterTargeta);
targeta.addEventListener('mouseleave', gestionarMouseLeaveTargeta);

Boton para limpiar el log:

botoNetejaLog.addEventListener('click', () => {
  log.innerHTML = '';
});

Alternativa moderna:
log.replaceChildren();

Nota: No añadimos mensaje de confirmacion porque entonces el log no quedaria vacio.

Sin stopPropagation:

contenidor.addEventListener('click', () => {
  afegeixAlLog('Clic al contenidor');
});

botoPropagacio.addEventListener('click', () => {
  afegeixAlLog('Clic al boto intern');
});

RESULTADO al clicar el boton:
1. 'Clic al boto intern'
2. 'Clic al contenidor' (propagacion/bubbling)

El evento sube desde el hijo al padre.

Usar event.stopPropagation() para evitar que el evento suba:

function gestionarClicBotoPropagacio(event) {
  event.stopPropagation();  // Detiene la propagacion
  afegeixAlLog('Clic al boto (propagacio aturada)');
}

botoPropagacio.addEventListener('click', gestionarClicBotoPropagacio);

RESULTADO:
- Clic en el boton: solo log del boton
- Clic en el contenidor (fuera boton): log del contenidor

document.addEventListener('DOMContentLoaded', () => {
  // Seleccionar elementos
  const targeta = document.getElementById('targeta');
  const log = document.getElementById('log');
  const llista = document.getElementById('llista');

  // Funcion auxiliar log
  function afegeixAlLog(text) {
    const li = document.createElement('li');
    li.textContent = text;
    log.appendChild(li);
  }

  // Listener targeta
  function gestionarClicTargeta(e) {
    afegeixAlLog(
      `currentTarget: ${e.currentTarget.tagName}, ` +
      `target: ${e.target.tagName}`
    );
  }

  targeta.addEventListener('click', gestionarClicTargeta);

  // Listeners lista
  llista.querySelectorAll('li').forEach(el => {
    el.addEventListener('click', () => {
      afegeixAlLog(`Element: ${el.textContent} (id: ${el.dataset.id})`);
    });
  });
});

removeEventListener requiere la MISMA referencia de funcion que addEventListener.

// ❌ NO funciona - funciones anonimas diferentes
targeta.addEventListener('click', () => { ... });
targeta.removeEventListener('click', () => { ... });

// ✅ FUNCIONA - misma referencia
function gestionarClick() { ... }
targeta.addEventListener('click', gestionarClick);
targeta.removeEventListener('click', gestionarClick);

En la practica, las funciones gestionarClicTargeta, gestionarMouseEnterTargeta, etc. deben ser nombradas.

Ejemplo completo de añadir elementos dinamicamente:

const botoAfegir = document.getElementById('afegir');
const llista = document.getElementById('llista');
let comptador = 0;

function afegirElement() {
  comptador++;

  // Crear nuevo elemento
  const nouElement = document.createElement('li');
  nouElement.textContent = 'Element ' + comptador;

  // Insertar en el DOM
  llista.appendChild(nouElement);
}

// Asignar listener
botoAfegir.addEventListener('click', afegirElement);

Cada clic crea un nuevo <li> y lo añade a la lista.

Boton que se auto-desactiva despues del primer uso:

const botoUnCop = document.getElementById('un-cop');

function gestionarClicUnCop() {
  // Crear y añadir elemento
  const li = document.createElement('li');
  li.textContent = 'Accio executada!';
  resultats.appendChild(li);

  // Eliminar el listener
  botoUnCop.removeEventListener('click', gestionarClicUnCop);

  // Cambiar aspecto del boton
  botoUnCop.textContent = 'Ja esta fet';
  botoUnCop.disabled = true;
}

botoUnCop.addEventListener('click', gestionarClicUnCop);

El primer clic ejecuta la accion y elimina el listener.

Casos de uso tipicos de removeEventListener:

1. Boton que solo debe funcionar durante un tiempo limitado
2. Cuando un juego ha terminado
3. Para bloquear una accion despues de usarla una vez
4. Limpieza de codigo antes de eliminar un elemento del DOM
5. Desactivar temporalmente una funcionalidad

Ejemplo - desactivar despues de un uso:
function accio() {
  // hacer algo...
  boto.removeEventListener('click', accio); // auto-desactivar
}
boto.addEventListener('click', accio);

El navegador identifica los listeners por su referencia:

// ❌ ERROR - funciones anonimas diferentes
boto.addEventListener('click', function() { ... });
boto.removeEventListener('click', function() { ... });
// Son dos objetos funcion distintos

// ✅ CORRECTO - misma referencia
function miFuncion() { ... }
boto.addEventListener('click', miFuncion);
boto.removeEventListener('click', miFuncion);
// Mismo objeto funcion

Consejo: Si necesitas eliminar un listener,
siempre usa una funcion nombrada.

Comportamiento por defecto (propagacion activa):

const caixa = document.getElementById('caixa');
const boto = document.getElementById('boto');

caixa.addEventListener('click', function() {
  console.log('Has clicat la CAIXA');
});

boto.addEventListener('click', function() {
  console.log('Has clicat el BOTO');
});

RESULTADO al clicar el boton:
1. 'Has clicat el BOTO' (primero el target)
2. 'Has clicat la CAIXA' (luego el padre)

El evento 'sube' desde el boton hasta el div.

Detiene la propagacion del evento hacia los elementos padre:

boto.addEventListener('click', function(event) {
  event.stopPropagation();  // ← Detiene aqui
  console.log('Solo el boton - no sube al div');
});

caixa.addEventListener('click', function() {
  console.log('Esto NO se ejecuta si clicas el boton');
});

COMPARACION:
- Sin stopPropagation: ambos listeners se ejecutan
- Con stopPropagation: solo el del boton

Util cuando tienes elementos anidados con listeners
y quieres evitar que el padre reaccione.

Caso tipico - boton dentro de una caja:

<div id="caixa">
  <p>Clica el boton de dins:</p>
  <button id="boto">Clica</button>
</div>

JS con stopPropagation:

caixa.addEventListener('click', function() {
  console.log('Caixa');
});

boto.addEventListener('click', function(e) {
  e.stopPropagation();
  console.log('Boto (propagacio aturada)');
});

RESULTADO:
- Clic en el boton: solo 'Boto'
- Clic en el div (fuera boton): 'Caixa'

Estructura tipica de trabajo con eventos y DOM:

// 1. SELECCIONAR elementos
const boton = document.getElementById('afegir');
const lista = document.getElementById('llista');

// 2. DEFINIR funcion manejadora
function añadirElemento() {
  const li = document.createElement('li');
  li.textContent = 'Nuevo elemento';
  lista.appendChild(li);
}

// 3. AÑADIR listener
boton.addEventListener('click', añadirElemento);

// 4. OPCIONAL: eliminar listener
// boton.removeEventListener('click', añadirElemento);

Este patron conecta eventos con manipulacion del DOM.

Cancela el comportamiento por defecto del navegador para un evento.

FORMULARIO (evitar envío):
formulario.addEventListener('submit', function(e) {
  e.preventDefault();
  // Validar datos con JavaScript antes de enviar
  const nombre = document.getElementById('nom').value.trim();
  if (nombre === '') {
    console.log('El nombre es obligatorio');
  } else {
    console.log('Formulario validado: ' + nombre);
  }
});

ENLACE (evitar navegación):
enlace.addEventListener('click', function(e) {
  e.preventDefault();
  alert('Navegación bloqueada con preventDefault()');
});

Técnica que consiste en asignar el listener al elemento PADRE y detectar qué HIJO recibió el evento mediante `e.target`.

Ventaja: los nuevos hijos añadidos dinámicamente heredan el comportamiento automáticamente.

EJEMPLO - Lista con tareas dinámicas:
const llista = document.getElementById('llista');
const botoAfegir = document.getElementById('afegir');
let comptador = 3;

// Un solo listener en el <ul> padre
llista.addEventListener('click', function(e) {
  if (e.target.tagName === 'LI') {
    alert('Has clicado: ' + e.target.textContent);
  }
});

// Añadir nuevas tareas (también funcionan)
botoAfegir.addEventListener('click', function() {
  comptador++;
  const novaTasca = document.createElement('li');
  novaTasca.textContent = 'Tasca ' + comptador;
  llista.appendChild(novaTasca);
});

Cada elemento tiene una propiedad style que corresponde al atributo HTML style.

Ejemplos:
elemento.style.color = 'red';
elemento.style.backgroundColor = 'lightyellow';
elemento.style.fontSize = '18px';
elemento.style.marginBottom = '1rem';

REGLAS IMPORTANTES:
- Las propiedades CSS con guion se convierten a camelCase
  background-color → backgroundColor
  font-size → fontSize
  margin-bottom → marginBottom
- Los valores son strings (con unidades si es necesario)

Dos formas de eliminar estilos inline:

// 1. Asignar cadena vacia (elimina todos)
elemento.style = '';

// 2. Eliminar propiedades especificas
elemento.style.color = '';
elemento.style.backgroundColor = '';

Ejemplo practico - boton reset:
botonReset.addEventListener('click', function() {
  targeta.style = '';
  parrafo.style = '';
  targeta.classList.remove('resaltat');
});

Al asignar '' se eliminan todos los estilos del atributo HTML style.

La propiedad className devuelve/modifica TODA la cadena de clases.

// LEER clases
console.log(elemento.className);  // "missatge info"

// SOBREESCRIBIR todas las clases (CUIDADO)
elemento.className = 'missatge avis';
// Resultado: pierde 'info', ahora solo tiene 'missatge avis'

// Añadir clase (forma manual con className)
elemento.className += ' nova-classe';

ATENCION: className reemplaza todas las clases. Para añadir/quitar clases individualmente, usar classList.

Metodo: elemento.classList.add('nombreClase')

Ejemplo:
const missatge = document.getElementById('missatge');

// Añadir una clase
missatge.classList.add('error');

// Añadir multiples clases
missatge.classList.add('clase1', 'clase2', 'clase3');

Caracteristicas:
- Si la clase ya existe, no hace nada (no duplica)
- Mas seguro que className += (evita espacios dobles)
- Metodo preferido para añadir clases

Metodo: elemento.classList.remove('nombreClase')

Ejemplo:
const missatge = document.getElementById('missatge');

// Eliminar una clase
missatge.classList.remove('info');

// Eliminar multiples clases
missatge.classList.remove('avis', 'error');

// Eliminar solo si existe
missatge.classList.remove('clase-que-puede-no-existir');  // No da error

Caracteristicas:
- Si la clase no existe, no da error
- Se pueden eliminar varias clases a la vez

Metodo: elemento.classList.toggle('nombreClase')

Ejemplo - alternar modo oscuro:
botonFosc.addEventListener('click', function() {
  document.body.classList.toggle('mode-fosc');
});

Funcionamiento:
- Si la clase NO existe → la AÑADE (return true)
- Si la clase EXISTE → la ELIMINA (return false)

Ejemplo practico - resaltar targeta:
botonResaltat.addEventListener('click', function() {
  targeta.classList.toggle('resaltat');
});
// Cada clic activa/desactiva el resaltado

Metodo: elemento.classList.contains('nombreClase')

Ejemplo - cambiar texto del boton segun estado:
botonToggle.addEventListener('click', function() {
  missatge.classList.toggle('ocult');

  if (missatge.classList.contains('ocult')) {
    botonToggle.textContent = 'Mostrem missatge';
  } else {
    botonToggle.textContent = 'Amaguem missatge';
  }
});

Devuelve:
- true si el elemento tiene la clase
- false si no la tiene

Util para condicionales y validaciones.

Patron tipico con classList.toggle() y clase CSS .ocult:

CSS:
.ocult {
  display: none;
}

JavaScript:
const botoToggle = document.getElementById('boto-missatge-toggle');
const missatge = document.getElementById('missatge');

botoToggle.addEventListener('click', function() {
  missatge.classList.toggle('ocult');

  // Actualizar texto del boton
  if (missatge.classList.contains('ocult')) {
    botoToggle.textContent = 'Mostrem missatge';
  } else {
    botoToggle.textContent = 'Amaguem missatge';
  }
});

Ventaja: separacion de responsabilidades (CSS define como ocultar, JS solo alterna la clase).

Patron completo para modo oscuro:

CSS:
.mode-fosc {
  background-color: #222;
  color: #f5f5f5;
}

.mode-fosc .targeta {
  background-color: #333;
  border-color: #555;
}

JavaScript:
botoModeFosc.addEventListener('click', function() {
  document.body.classList.toggle('mode-fosc');

  if (document.body.classList.contains('mode-fosc')) {
    missatge.textContent = 'Estat: mode fosc activat';
  } else {
    missatge.textContent = 'Estat: mode clar activat';
  }
});

Consejo: aplicar la clase al body para que afecte a toda la pagina.

Patron para cambiar entre estados (info, avis, error):

function mostrarMissatge(tipus, text) {
  // Eliminar clases de estado anteriores
  missatge.classList.remove('info', 'avis', 'error');

  // Añadir la nueva clase
  missatge.classList.add(tipus);

  // Actualizar texto
  missatge.textContent = text;
}

// Uso:
botoInfo.addEventListener('click', function() {
  mostrarMissatge('info', 'Informacio general');
});

botoAvis.addEventListener('click', function() {
  mostrarMissatge('avis', 'Atencio necessaria');
});

botoError.addEventListener('click', function() {
  mostrarMissatge('error', 'Error produit');
});

Ejemplo de modificaciones comunes:

const targeta = document.getElementById('targeta');

// Centrar elemento
targeta.style.margin = '0 auto';  // arriba/abajo 0, izquierda/derecha auto

// Ancho maximo
