Los valores deben incluir unidades cuando sea necesario (px, rem, %).

Patron completo para un panel de control:

document.addEventListener('DOMContentLoaded', function() {
  // Seleccionar elementos
  const targeta = document.getElementById('targeta');
  const text = document.getElementById('text-principal');
  const missatge = document.getElementById('missatge');

  // Ajustes iniciales con style
  targeta.style.maxWidth = '600px';
  targeta.style.margin = '0 auto';

  // Boton texto rojo
  document.getElementById('boto-vermell').addEventListener('click', function() {
    text.style.color = 'red';
  });

  // Boton alternar resaltado
  document.getElementById('boto-resaltat').addEventListener('click', function() {
    targeta.classList.toggle('resaltat');
  });

  // Boton reset
  document.getElementById('boto-reset').addEventListener('click', function() {
    targeta.style = '';
    text.style = '';
    targeta.classList.remove('resaltat');
  });
});

Patron para validacion visual de formularios:

// CSS previo:
// .camp-error { border-color: red; background-color: #ffe6e6; }
// .mensaje-error { color: red; display: none; }
// .mensaje-error.visible { display: block; }

// JavaScript:
form.addEventListener('submit', function(event) {
  event.preventDefault();

  // Limpiar errores anteriores
  campNom.classList.remove('camp-error');
  errorNom.classList.remove('visible');

  let hiHaErrors = false;

  // Validar nombre (minimo 2 caracteres)
  if (campNom.value.trim().length < 2) {
    hiHaErrors = true;
    campNom.classList.add('camp-error');
    errorNom.classList.add('visible');
  }

  // Validar email (contiene @)
  if (!campEmail.value.includes('@')) {
    hiHaErrors = true;
    campEmail.classList.add('camp-error');
    errorEmail.classList.add('visible');
  }

  if (!hiHaErrors) {
    // Enviar formulario
  }
});

Patron para resetear estados de error:

// Antes de validar, eliminar todas las clases de error
campNom.classList.remove('camp-error');
campEmail.classList.remove('camp-error');
campMissatge.classList.remove('camp-error');

errorNom.classList.remove('visible');
errorEmail.classList.remove('visible');
errorMissatge.classList.remove('visible');

// Ocultar mensaje de exito
mensajeOk.style.display = 'none';

let hiHaErrors = false;

// Ahora realizar validaciones...

// Si todo correcto
if (!hiHaErrors) {
  mensajeOk.style.display = 'block';
  form.reset(); // Vaciar campos
}

Importante: Siempre limpiar errores antes de validar para evitar acumulacion de estados.

Ejemplo - reemplazar parrafo con HTML formateado:

const resum = document.getElementById('resum');
resum.innerHTML = 
  'Aquest cataleg <strong>actualitzat dinamicament</strong> ' +
  'mostra productes en temps real. <a href="#">Mes informacio</a>.';

// Añadir salto de linea adicional
resum.innerHTML += '<br>Amb JavaScript i el DOM.';

Caracteristicas:
- Interpreta etiquetas HTML
- Permite formato (negrita, enlaces, etc.)
- Riesgo de XSS si el contenido viene de usuario

Dos formas de cambiar atributos:

// 1. Con setAttribute (generico)
const enllac = document.getElementById('enllac-botiga');
enllac.setAttribute('href', 'https://www.ioc.cat');
enllac.setAttribute('title', 'Obre la nova botiga de l'IOC');

// 2. Como propiedad directa (mas corto)
enllac.href = 'https://www.ioc.cat';

// Verificar el cambio
console.log(enllac.getAttribute('href')); // https://www.ioc.cat

HTML:
<li class="producte" data-preu="9.99">...</li>

JavaScript:
const primerProducte = document.querySelector('.producte');

// LEER data-preu
const preuActual = primerProducte.dataset.preu;
console.log(preuActual); // "9.99"

// MODIFICAR data-preu
primerProducte.dataset.preu = '14.5';

// Actualizar el texto visible
const preuText = primerProducte.querySelector('.preu-producte');
preuText.textContent = '14,50 €';

Nota: dataset converte data-preu a dataset.preu (camelCase)

Ejemplo completo - crear elemento de producto:

// 1. Crear el li contenedor
const nouProducte = document.createElement('li');
nouProducte.className = 'producte';
nouProducte.dataset.preu = '5.99';

// 2. Crear nombre del producto
const nom = document.createElement('strong');
nom.className = 'nom-producte';
nom.textContent = 'Nou Producte A';

// 3. Crear precio
const preu = document.createElement('span');
preu.className = 'preu-producte';
preu.textContent = '5,99 €';

// 4. Anadir partes al li
nouProducte.appendChild(nom);
nouProducte.appendChild(preu);

// 5. Anadir a la lista
llista.appendChild(nouProducte);

Metodo prepend() - inserta como primer hijo:

const llista = document.getElementById('llista-productes');

// Crear nuevo producto
const producteInicial = document.createElement('li');
producteInicial.className = 'producte';
producteInicial.dataset.preu = '12.00';
producteInicial.innerHTML = 
  '<strong class="nom-producte">Producte Inicial</strong>' +
  '<span class="preu-producte">12,00 €</span>';

// Insertar al PRINCIPIO de la lista
llista.prepend(producteInicial);

// Comparacion:
// prepend() → al principio
// append() o appendChild() → al final

Patron plantilla - clonar desde elemento oculto:

// 1. Obtener la plantilla
const plantilla = document.getElementById('plantilla-producte');

// 2. Clonar CON todo su contenido
const clon = plantilla.cloneNode(true);

// 3. IMPORTANTE: eliminar el id para evitar duplicados
clon.removeAttribute('id');

// 4. Personalizar el clon
clon.dataset.preu = '19.99';
clon.querySelector('.nom-producte').textContent = 'Producte clonat';
