Lista de respuestas con DOM vanilla:

function renderList() {
  // Vaciar lista
  answersList.innerHTML = '';

  // Crear elementos para cada respuesta
  answers.forEach((value, index) => {
    const li = document.createElement('li');

    // Span con la puntuacion
    const spanValue = document.createElement('span');
    spanValue.className = 'value';
    spanValue.textContent = `Puntuacion: ${value}`;

    // Boton para eliminar
    const btnDelete = document.createElement('button');
    btnDelete.textContent = 'Borrar';
    btnDelete.addEventListener('click', () => {
      answers.splice(index, 1);
      updateAll();
    });

    li.appendChild(spanValue);
    li.appendChild(btnDelete);
    answersList.appendChild(li);
  });
}

Estadisticas de la encuesta:

function renderStats() {
  if (answers.length === 0) {
    stats.textContent = 'Aun no hay respuestas.';
    return;
  }

  // Calcular suma
  const sum = answers.reduce((acc, v) => acc + v, 0);

  // Calcular media
  const avg = sum / answers.length;

  // Mostrar resultado
  stats.textContent = 
    `Tenemos ${answers.length} respuestas. ` +
    `Media: ${avg.toFixed(2)} sobre 5.`;
}

METODOS USADOS:
- reduce(): sumar todos los valores
- toFixed(2): redondear a 2 decimales

