SERVIDOR EXPRESS CON SQLITE:
const sqlite3 = require('sqlite3');
const db = new sqlite3.Database('./datos.db');

// Crear tabla
db.run(`CREATE TABLE IF NOT EXISTS contactos (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  nom TEXT NOT NULL,
  correu TEXT NOT NULL
)`);

// Ruta POST
app.post('/formulario', (req, res) => {
  const { nom, correu } = req.body;
  if (!nom || !correu) return res.status(400).send('Faltan campos');
  db.run('INSERT INTO contactos (nom, correu) VALUES (?, ?)', [nom, correu]);
  res.send(`<h2>Datos recibidos</h2><p>Nombre: ${nom}</p><p>Correo: ${correu}</p>`);
});

1. Crear el objeto: `const xhr = new XMLHttpRequest()`
2. Configurar con open(): `xhr.open('GET', 'url', true)`
3. (Opcional) Añadir cabeceras con setRequestHeader()
4. Definir qué hacer al recibir respuesta (onreadystatechange)
5. Enviar la petición: `xhr.send()`

Ejemplo:
const xhr = new XMLHttpRequest();
xhr.open('GET', 'datos.txt', true);
xhr.onreadystatechange = function() {
  if (xhr.readyState === 4 && xhr.status === 200) {
    console.log(xhr.responseText);
  }
};
xhr.send();

readyState indica en qué punto está la petición:

• 0 - UNSENT: creado pero aún no se llamó a open()
• 1 - OPENED: se llamó a open(), pero no a send()
• 2 - HEADERS_RECEIVED: cabeceras de la respuesta recibidas
• 3 - LOADING: la respuesta se está recibiendo
• 4 - DONE: la petición ha terminado, respuesta completa

Patrón típico:
if (xhr.readyState === 4 && xhr.status === 200) {
  // respuesta lista y exitosa
}

1. Leer responseText (cadena de texto)
2. Convertir con JSON.parse() a objeto/array JavaScript
3. Recorrer los datos y actualizar el DOM

Ejemplo:
xhr.onreadystatechange = function() {
  if (xhr.readyState === 4 && xhr.status === 200) {
    const productos = JSON.parse(xhr.responseText);
    productos.forEach(p => {
      const li = document.createElement('li');
      li.textContent = `${p.nom} - ${p.preu} €`;
      lista.appendChild(li);
    });
  }
};

1. Usar open() con método 'POST'
2. Establecer cabecera Content-Type
3. Enviar datos en send()

Ejemplo:
const xhr = new XMLHttpRequest();
xhr.open('POST', 'procesar.php', true);
xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');

const datos = 'nombre=Anna&edad=20';
xhr.onreadystatechange = function() { /* ... */ };
xhr.send(datos);

Para JSON:
xhr.setRequestHeader('Content-Type', 'application/json');
xhr.send(JSON.stringify({ nombre: 'Anna', edad: 20 }));

ERROR DE RED:
xhr.onerror = function() {
  console.log('Error de red');
};

TIMEOUT (tiempo máximo de espera):
xhr.timeout = 5000; // 5 segundos
xhr.ontimeout = function() {
  console.log('La petición tardó demasiado');
};

Siempre comprobar status:
if (xhr.readyState === 4) {
  if (xhr.status === 200) { /* éxito */ }
  else { /* error HTTP */ }
}

fetch() hace peticiones HTTP y devuelve una Promise que se resuelve con un objeto Response.

GET básico:
fetch('datos.txt')
  .then(response => {
    if (!response.ok) throw new Error('Error HTTP: ' + response.status);
    return response.text();
  })
  .then(texto => console.log(texto))
  .catch(error => console.log('Error:', error));

Ventajas sobre XHR:
• Sintaxis más simple y declarativa
• Uso nativo de Promesas
• No necesita readyState
• response.ok verifica si status es 200-299

LEER JSON:
fetch('productos.json')
  .then(response => {
    if (!response.ok) throw new Error('Error');
    return response.json(); // Convierte directamente a objeto JS
  })
  .then(productos => productos.forEach(p => console.log(p.nom)))
  .catch(error => console.log(error));

ENVIAR POST CON JSON:
fetch('/api/agregar', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ nombre: 'Producto C', precio: 12.5 })
})
  .then(response => response.json())
  .then(resultado => console.log('Guardado:', resultado))
  .catch(error => console.log('Error:', error));

async/await (ES2017) permite escribir código asíncrono como si fuera síncrono.

REGLAS:
• async antes de function → siempre devuelve una Promise
• await delante de una Promise → pausa hasta que se resuelva
• No bloquea el resto de la página

EJEMPLO:
async function cargarProductos() {
  try {
    const response = await fetch('productos.json');
    if (!response.ok) throw new Error('Error HTTP: ' + response.status);
    const productos = await response.json();
    productos.forEach(p => console.log(p.nom, '-', p.preu));
  } catch (error) {
    console.log('Error:', error);
  }
}

Con fetch encadenando .then():
function getUserAndPosts(postId) {
  fetch(`https://jsonplaceholder.typicode.com/posts/${postId}`)
    .then(r => r.json())
    .then(post => {
      return fetch(`https://jsonplaceholder.typicode.com/users/${post.userId}`);
    })
    .then(r => r.json())
    .then(user => console.log('Usuario:', user))
    .catch(e => console.error(e));
}

Con async/await (más limpio):
async function getUserAndPosts(postId) {
  try {
    const postRes = await fetch(`...posts/${postId}`);
    const post = await postRes.json();
    const userRes = await fetch(`...users/${post.userId}`);
    const user = await userRes.json();
    console.log('Usuario:', user);
  } catch(e) { console.error(e); }
}

Promise.all() ejecuta varias promesas en paralelo y espera a que TODAS terminen.

EJEMPLO (Ghibli API - película + personajes):
const response = await fetch(apiUrl);
const data = await response.json();

// Array de promesas para cada personaje
const personajesPromises = data.people.map(url =>
  fetch(url).then(res => res.json())
);

// Esperar a que TODAS terminen
const personajesData = await Promise.all(personajesPromises);
const nombres = personajesData.map(p => p.name);

Ventaja: no necesitas contar manualmente cuándo han terminado todas.

BACKEND (server.js):
const express = require('express');
const sqlite3 = require('sqlite3');
const cors = require('cors');

app.use(express.json());
app.use(cors());

const db = new sqlite3.Database('./tasks.db');
db.run('CREATE TABLE IF NOT EXISTS tasks (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  text TEXT NOT NULL,
  completed BOOLEAN DEFAULT false
)');

// Rutas CRUD:
app.get('/tasks', (req, res) => { db.all('SELECT * FROM tasks', ...) });
app.post('/tasks', (req, res) => { db.run('INSERT INTO tasks...', ...) });
app.put('/tasks/:id', (req, res) => { db.run('UPDATE tasks...', ...) });
app.delete('/tasks/:id', (req, res) => { db.run('DELETE FROM tasks...', ...) });

